-- Project 2: 第二阶段：杰提计划
UPDATE course_contents
SET week_plan = '[{"week": 2, "theme": "第二周：成为实验建筑师", "goals": "学习科学实验设计的核心原则--变量控制、随机化、盲法与数据记录。基于上周提出的研究问题，设计出一套完整的、可以在自己家庭环境中执行的原创实验方案。", "activities": [{"day": "8-9", "title": "科学方法论入门（上）：控制你的“变量” (Scientific Methodology 101 (Part 1): Controlling Your Variables)", "duration": "约60分钟，可在2天内完成", "description": "青年研究员，上周我们提出了一个绝妙的核心问题。但这就像有了一张藏宝图，我们还需要建造一艘坚固的船才能出海寻宝。这艘船，就是我们的**“实验设计方案”**。\n建造这艘船的第一块龙骨，叫做**“变量控制”**。\n在科学实验中，“变量”指的是那些可能会改变的东西。为了让我们的实验可信，我们必须像侦探一样，把所有可能影响结果的“嫌疑变量”都控制住，只留下我们真正想研究的那一个。\n自变量 (Independent Variable): 这是我们主动改变的东西，是我们想测试其效果的“原因”。在我们的实验中，自变量就是**“主人的状态”**（是决定回家了，还是没决定）。\n因变量 (Dependent Variable): 这是我们观察和测量的东西，是我们想看的“结果”。在我们的实验中，因变量就是**“宠物的行为”**（是否表现出等待）。\n控制变量 (Controlled Variables): 这是所有其他可能影响“结果”的因素，我们必须努力让它们保持不变。这些就是我们上周讨论过的各种“干扰”！\n思考挑战：\n回想一下谢尔德雷克博士的实验，他都控制了哪些变量？\n他让主人随机时间回家，是为了控制【习惯/", "deliverables": ["你的“变量控制清单”：", "在下方的文本框中，列出你认为在你的实验中需要控制的所有变量", "清单越详细，你的“船”就越坚固！"]}, {"day": "10-12", "title": "科学方法论入门（下）：随机、双盲与量子骰子 (Scientific Methodology 101 (Part 2): Randomization, Double-Blind & The Quantum Die)", "duration": "约75分钟，可在3天内完成", "description": "青年研究员，我们已经学会了如何控制那些看得见的“变量”。但科学中最强大的敌人，是我们自己--我们大脑的期望和偏见。为了战胜这个敌人，科学家发明了两件强大的“隐形盔甲”：随机化 和 盲法。\n想象一位魔法师发明了一种“快乐药水”。他找来10个志愿者测试。他给其中5个他认为会喜欢药水的人喝了药水，给另外5个他觉得比较挑剔的人喝了白水。结果，喝了药水的人都说感觉很快乐！\n这个实验可靠吗？\n不可靠！因为魔法师的期望已经影响了实验。他可能对喝药水的人更热情，对喝白水的人很冷淡，这种态度本身就可能让人感到快乐或不快乐。\n如何改进？\n随机化 (Randomization): 用抛硬币的方式决定谁喝药水，谁喝白水。这样就消除了魔法师的主观选择偏见。\n盲法 (Blind):\n单盲 (Single-Blind): 不告诉志愿者他们喝的是什么。这样志愿者的期望就不会影响结果。\n双盲 (Double-Blind): 魔法师自己也不知道哪瓶是药水，哪瓶是白水（让他的助手贴上A、B标签）。只有在实验结束后，助手才公布答案。这样，魔法师在互动时的无意识偏见也被消除了。\n现在，回到我们的实验：\n随机化： 我们如何决定主", "deliverables": ["你的“双盲思考”：", "在下方的文本框中，回答以下问题：", "问题： 在我们的实验里，如果不由盖亚来自动分析视频，而是由你自己亲自观看录像来判断宠物“是否在等待”，你认为“双盲”有多重要？请描述一个**你可能会无意中犯下的“偏见错误”**的例子"]}, {"day": "13-14", "title": "撰写你的实验方案 (Writing Your Experimental Protocol)", "duration": "约60分钟，可在2天内完成", "description": "青年研究员，现在你已经掌握了所有的理论工具，是时候把它们组合起来，绘制出我们“杰提计划”的最终蓝图--一份完整的、可执行的实验方案了。\n这份方案将是你未来几周行动的唯一指南。它必须像一份食谱或一份建筑图纸一样，清晰、准确、无可挑剔。\n请你在你的数字日记或纸质日记中，完整地写下你的实验方案。它应该包含以下部分：\n研究问题： (从上周的作业中复制过来)\n实验假设 (Hypothesis): (你预测的结果是什么？)\n例如：我假设，宠物开始等待的时间与主人‘做出回家决定’的时刻显著相关。\n实验材料 (Materials):\n例如：一台可以录像的手机或摄像头、一个三脚架、宠物的等待区域（如门口的垫子）、一个可以上网并使用盖亚App的手机（供离家的主人使用）、我的《第六感日记》本。\n实验步骤 (Procedure): (这是最重要的部分，请尽可能详细！)\n准备阶段： 离家的主人(A)和留守的观察员(B)约定好大致的实验时间窗口（例如下午3-5点）。B在家中架设好摄像头，确保能清晰拍到宠物的“等待区域”。\n出发： A正常离家，到达一个离家至少5公里以外的地点（例如办公室、咖啡馆），我们称之为“决定", "deliverables": ["你的完整实验方案：", "请在下方的文本框中，打字输入你最终版本的、完整的实验方案", "请确保包含了上述所有五个部分"]}]}, {"week": 3, "theme": "第三周：扬帆起航--首次数据航行", "goals": "将上周设计的实验方案付诸实践。成功完成至少两次完整的实验数据收集，包括视频录制、时间点标记和数据上传。学习如何应对实验过程中可能出现的各种意外状况。", "activities": [{"day": "15", "title": "出航前检查：设备调试与场地布置 (Pre-voyage Check: Equipment & Site Setup)", "duration": "约45分钟", "description": "青年研究员，我们的“科学之船”--实验方案已经绘制完毕。但在真正出海之前，一位谨慎的船长必须对船上的每一个部件进行最后的检查。今天，我们的任务就是确保所有“设备”都处于最佳状态。\n请逐项检查并确认：\n摄像设备：\n¨ \n找一个手机或摄像头，确保它有足够的电量（最好全程插着电源）和足够的存储空间（至少能录制2-3小时）。\n¨ \n清洁镜头，确保画面清晰。\n拍摄角度与场地：\n¨ \n找到一个最佳的拍摄位置。这个位置需要满足：\n能完整、清晰地拍到你定义的“等待区域”（比如门口的垫子、窗台）。\n不会轻易被宠物撞倒。\n不会妨碍家人正常走动。\n¨ \n用三脚架、书本或其他东西固定好你的摄像设备，确保它在长时间录制中不会移动。\n“等待区域”定义：\n¨ \n明确你实验中的“等待区域”是哪里。是一块特定的地垫？是窗户前一米内的范围？请在你的《第六感日记》中用文字或画图的方式把它精确地定义下来。这对于后续盖亚进行视频分析至关重要。\n离家主人的准备：\n¨ \n确保离家的家人（实验员A）的手机上，能够顺利访问我们的网站和盖亚App。\n¨ \n与家人一起再次熟悉实验流程，特别是如何使用App上的“开始实验”、“我已决定”和“", "deliverables": ["你的“准备就绪”证明：", "拍照上传一张你的“实验场地”照片", "照片中需要能清晰地看到你架设好的摄像设备以及它所对准的“等待区域”"]}]}, {"week": 1, "theme": "第一周：打破常规--当科学遇到“不可能”", "goals": "从“宠物有第六感吗？”的现象层面，深入到“这种‘感应’的本质是什么？”的理论层面。通过案例学习和批判性思维训练，理解常规科学解释的局限性，并正式引入“心灵感应”作为一种需要被严谨检验的科学假说。", "activities": [{"day": "1-2", "title": "案例深度分析：杰提实验的背后 (Case Deep Dive: Behind the Jaytee Experiments)", "duration": "约60分钟，可在2天内完成", "description": "你已经不再是“宠物侦探”，而是升级为“青年研究员”了。欢迎来到这个计划，它的名字来源于那只传奇小狗--杰提。在这里，我们将不再满足于“是什么”，而是要勇敢地追问“为什么”和“怎么样”。\n在开始之前，我们需要更深入地了解一下科学家们到底对杰提做了些什么。这不再是一个简单的故事，而是一个真实的科学案例。\n还记得杰提的故事吗？科学家鲁珀特·谢尔德雷克博士为了排除所有已知的可能性，设计了一系列非常巧妙的实验。\n排除【习惯】和【时间感】： 博士让杰提的主人帕姆在完全随机的时间回家。他会给帕姆打电话说：“现在就出发！”这样，杰提就不可能根据“差不多该到时间了”的习惯来等待。\n排除【听觉】： 他让帕姆乘坐完全陌生的出租车回家。这样，就没有了熟悉的引擎声。实验地点离家很远，有时超过20英里，任何声音都不可能传到。\n排除【嗅觉】： 在某些实验中，帕姆会逆风回家，确保她的气味不会被风提前吹到家里。\n排除【家中线索】： 实验的关键是，在帕姆出发前，家里的其他人完全不知道她什么时候会回来。这样，他们就不会因为期待而无意中做出一些小动作（比如开始准备晚餐）来提示杰提。\n实验结果是什么呢？\n在数百次录像实验中，结", "deliverables": ["你的“头脑风暴”：", "在下方的文本框中，至少列出两个你认为谢尔德雷克博士的实验可能还存在的“漏洞”或“未排除的干扰因素”", "格式："]}, {"day": "3-5", "title": "理论武装：什么是“非定域性”？ (Theoretical Toolkit: What is ''Non-Locality''?)", "duration": "约75分钟，可在3天内完成", "description": "青年研究员，你上一个任务提出的质疑非常棒！这正是科学精神的体现。\n现在，我们要进入一个更深、也更奇妙的领域。谢尔德雷克博士和一些物理学家提出了一个大胆的假说：杰提的“感应”可能不是通过任何我们已知的、需要时间在空间中传播的信号（比如声音、光、气味），而是一种**“非定域性”（Non-Locality）**的连接。\n这是个听起来很酷的词，但它到底是什么意思呢？\n想象一下，我（盖亚）给了你和你的好朋友一人一颗非常神奇的骰子。这两颗骰子是一对“双胞胎”，它们被施加了魔法。\n魔法规则是：无论你们相隔多远--你在北京，你的朋友在纽约--只要你们在同一时刻掷出骰子，你们看到的结果永远是相反的。 如果你掷出的是“1”，他掷出的就一定是“6”；如果你掷出“3”，他就一定是“4”。反之亦然。\n重要的是，在你掷出骰子之前，没有任何人--包括你自己和我--知道你会掷出几点。结果是完全随机的。但是，一旦你掷出了“1”，在地球另一端的你朋友的骰子，就在那一瞬间，“知道”了它必须显示为“6”。\n这个信息（“这边是1，你那边必须是6”）的传递，似乎没有花费任何时间，它好像瞬间跨越了整个地球。\n这就是“非定域性”的一", "deliverables": ["你的理解与推论：", "在下方的文本框中，回答以下两个问题：", "问题A： 请用你自己的话，简单解释一下什么是“非定域性”"]}, {"day": "6-7", "title": "提出你的研究问题 (Formulating Your Research Question)", "duration": "约30分钟，可在2天内完成", "description": "青年研究员，我们已经分析了案例，学习了前沿的理论。现在，是时候将这些知识转化为我们自己项目的核心了。\n科学研究的第一步，也是最重要的一步，就是提出一个清晰的、可被检验的研究问题。\n基于我们本周的学习，我们的核心挑战是：如何设计一个实验，来区分两种可能性？\n可能性1（经典信号假说）： 宠物是通过感知主人**开始回家这个【物理行为】**所产生的某种未知信号（这种信号需要时间传播）来做出反应的。\n可能性2（非定域性假说）： 宠物是直接感知到了主人做出回家这个【纯粹意念】，这种感知是瞬时的，与物理行为的开始无关。\n将上述两种可能性，转化为一个清晰的、可以用“是”或“否”来回答的研究问题。一个好的研究问题应该是具体的、可操作的。\n提交你的核心研究问题：\n在下方的文本框中，写下你为我们接下来的项目所确立的核心研究问题。\n没有标准答案，但一个好的例子是：\n“在排除了所有已知感官线索的条件下，家养宠物产生预期主人回家行为的时间点，是与主人‘做出回家决定’的时刻更相关，还是与主人‘开始物理移动’的时刻更相关？”\n非常出色，青年研究员！你已经完成了第一周的理论武装。你不仅理解了问题的复杂性，还掌握了前沿的", "deliverables": ["你的核心研究问题：", "在下方的文本框中，写下你为我们接下来的项目所确立的核心研究问题", "没有标准答案，但一个好的例子是："]}, {"day": "16-18", "title": "第一次试航：完成首次完整实验 (Maiden Voyage: Completing the First Full Experiment)", "duration": "实验本身根据你的方案进行，记录和上传约30分钟，可在3天内选择一天完成", "description": "青年研究员，一切准备就绪。今天，我们将进行第一次完整的实验。请严格按照你上周制定的实验方案执行。\n在与家人（实验员A）约定的时间窗口开始前，架设好摄像设备并开始录制。\n确保家中环境尽可能保持日常状态，不要因为正在实验而表现得过于紧张或不同寻常。正常看书、做作业即可。\n实验过程中，不要主动与宠物互动，让它自然地行动。\n当家人A回家后，停止录制。\n到达“决定点A”后，在约定的时间窗口内，打开盖亚App，点击“开始实验”。\n完全遵从量子随机数生成器的指令（“1”或“0”）。这是保证实验严谨性的核心！\n在App生成结果的瞬间，立刻点击“我已决定”(T1)。\n如果指令是“1”（立刻回家），在你实际迈出第一步或发动汽车的瞬间，立刻点击“我已出发”(T2)。\n正常回家。\n将今天录制的完整视频上传到盖亚的“数据保险库”。\n在你的《第六感日记》中，新开一页，记录本次实验的基本信息。模板如下：\n杰提计划 - 实验记录 第 [ 1 ] 次\n \n实验日期\n \n随机指令\n立刻回家 / 延迟回家 (请圈出)\nT1 (决定时刻)\n（盖亚App会自动记录，你可以在历史记录中查看并抄录）\nT2 (出发时刻)\n（盖亚Ap", "deliverables": ["你的实验日志：", "拍照上传你手写的本次《实验记录》页", "或者，打字输入表格中的所有内容"]}, {"day": "19-21", "title": "第二次远航：重复实验与问题解决 (Second Voyage: Repetition & Troubleshooting)", "duration": "实验本身根据你的方案进行，记录和上传约30分钟，可在3天内选择一天完成", "description": "青年研究员，恭喜你完成了第一次实验！但科学研究中，一次的结果可能是巧合。只有能够被重复验证的现象，才具有真正的科学价值。\n因此，本周的最后一个任务，就是再进行一次完整的实验。\n完全重复上一次实验的流程。\n吸取教训： 如果第一次实验中出现了任何意外情况（比如设备问题、环境干扰），请在这次实验前想办法解决或避免。\n手机没电了？ -> 这次全程充电。\n噪音太大了？ -> 尽量选择一个更安静的时间段。\n拍摄角度不好？ -> 重新调整你的机位。\n学习科学研究中最重要的品质之一：耐心和严谨。即使过程很枯燥，也要坚持严格执行方案。\n学习如何从失败或不完美的实验中吸取教训，并迭代改进。这就是“故障排除”（Troubleshooting）的能力。\n确认数据上传：\n在下方的文本框中，输入“第二次实验视频已上传完毕。”\n提交你的实验日志：\n拍照上传你手写的本次《实验记录》页。或者，打字输入表格中的所有内容。\n提交你的“故障排除”报告：\n在下方的文本框中，简要回答：\n问题： 在这两次实验中，你遇到的最大挑战是什么？你是如何解决的，或者你计划如何改进？\n示例回答： “我遇到的最大挑战是，我的猫大部分时间都待在它", "deliverables": ["你的实验日志：", "拍照上传你手写的本次《实验记录》页", "或者，打字输入表格中的所有内容"]}]}, {"week": 4, "theme": "第四周：深入航行与初步发现", "goals": "至少再完成两次完整的实验数据收集，使总数据量达到4次或以上。接收并学习解读盖亚提供的第一份《初步数据分析报告》，将抽象的数据与具体的宠物行为联系起来，并记录下自己的初步洞察。", "activities": [{"day": "22-25", "title": "第三次与第四次数据航行 (Third & Fourth Data Voyages)", "duration": "每次实验根据方案进行，记录和上传约30分钟。可在4天内选择两天完成", "description": "青年研究员，你的数据保险库里已经有了两次航行的宝贵记录。但在科学的海洋里，样本量越大，我们得出的结论就越不容易被偶然的风浪所倾覆。为了让我们能更清晰地看到现象背后的模式，本周我们需要再次出航两次。\n坚持标准： 继续严格按照你制定的实验方案，完成第三次和第四次实验。每一次的严谨，都是对最终结果的负责。\n优化流程： 根据前两次的经验，你的操作应该会更加熟练。思考一下，还有没有哪些小细节可以优化，让实验过程更顺畅？\n详细记录： 不要忽略每一次的实验日志记录。即使看起来和前两次没什么不同，也要把“随机指令”和“意外情况”等信息完整地记录下来。有时候，重大的发现就隐藏在那些看似不起眼的“意外”之中。\n体会“重复性实验”在科学研究中的核心地位。为什么科学家们总是强调“可重复性”？\n在重复的过程中，你的观察力可能会变得更加敏锐。留意一下，除了“去门口等待”，你的宠物是否还有其他一些更细微的、与主人回家相关的“仪式性”行为？\n提交第三次实验数据与日志：\n在下方的文本框中输入“第三次实验视频已上传完毕。”\n拍照上传你手写的第三次《实验记录》或打字输入其内容。\n提交第四次实验数据与日志：\n在下方的文本框中", "deliverables": ["第三次实验数据与日志：", "在下方的文本框中输入“第三次实验视频已上传完毕", "”"]}, {"day": "26-27", "title": "接收情报：解读你的第一份数据报告 (Receiving Intel: Interpreting Your First Data Report)", "duration": "约60分钟，可在2天内完成", "description": "青年研究员，祝贺你！你已经积累了足够进行初步分析的数据量。现在，盖亚已经将你上传的4份视频，根据你定义的“等待区域”和标记的T1（决定时刻）、T2（出发时刻），进行了自动分析。\n你将收到一份为你量身定制的《初步数据分析报告》。这份报告将用图表的形式，直观地展示你宠物的行为模式。\n你的报告将包含以下图表，请仔细阅读图表的说明：\n图表一：行为时间轴 (Behavior Timeline)\n这是一个展示宠物在“等待区域”行为的详细时间图。\n横轴(X轴)： 是时间，以实验员A“做出回家决定”（T1）的时刻为中心点“0”。负数代表决定前的分钟数，正数代表决定后的分钟数。\n纵轴(Y轴)： 每一行代表你的一次实验（实验1、2、3、4）。\n蓝色标记： 在时间轴上，如果某一分钟内，你的宠物在“等待区域”停留超过了10秒，这一分钟就会被标记为蓝色。\n重要标记： 图上会用一个红色箭头标出 T1 (决定时刻)，用一个绿色箭头标出 T2 (出发时刻)。\n你需要观察： 蓝色的标记是不是更频繁地出现在红色箭头（T1）之后？还是绿色箭头（T2）之后？或者毫无规律？\n图表二：关键时段统计 (Key Period Sta", "deliverables": ["你的数据解读：", "在下方的文本框中，根据你自己的报告，回答以下问题：", "问题1 (关于图表一): 在你的4次实验中，宠物开始等待的蓝色标记，更倾向于出现在红色箭头(T1)之后，还是绿色箭头(T2)之后？或者没有明显的规律？"]}, {"day": "28", "title": "本周复盘：数据与直觉 (Weekly Review: Data vs. Intuition)", "duration": "约20分钟", "description": "青年研究员，你已经像一位真正的数据科学家一样，分析了你的第一份报告。现在，让我们来做一个有趣的对比。\n有时候，冰冷的数据和我们作为观察者的“直觉”或“感觉”可能不完全一样。这是一个很好的机会，来思考科学研究中“客观数据”和“主观观察”的关系。\n回顾你过去几周所有的日记，特别是那些描述宠物行为的文字和图画。再看看你刚刚分析的数据图表。\n发布你的“研究员手记”：\n在下方的“全球研究员论坛”文本框中，分享你的思考。\n格式：\n手记标题： （例如：“图表之外的发现” 或 “我的数据和我想的不一样！”）\n我的手记： （例如：“我的数据显示，我的狗狗在‘意念期’的等待时间确实增加了。但有趣的是，我回顾日记发现，有一次它虽然没有去门口，但在主人决定回家的那一刻，它突然停止追逐尾巴，抬头朝门口的方向看了一会儿。这个行为没有被数据捕捉到，但我感觉那也是一种反应！这让我觉得，也许我们需要一个更聪明的指标来定义‘等待’。”）\n干得漂亮！第四周的任务完成了。你不仅积累了关键的数据，更重要的是，你已经开始学习如何像一个真正的研究者那样，在客观数据和生动观察之间建立桥梁，并从中提出更深刻的洞见。你的项目已经进入了深", "deliverables": ["思考一个问题：如果我们做了100次实验，是不是比只做6次实验得出的结论更可靠？为什么？这背后就是统计学中“样本量”的概念", "提交第五次实验数据与日志：", "在下方的文本框中输入“第五次实验视频已上传完毕"]}]}]'::jsonb,
    updated_at = NOW()
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 2;

-- Project 3: 第三阶段：贝尔不等式与生命系统
UPDATE course_contents
SET week_plan = '[{"week": 1, "theme": "第一周：爱因斯坦的“噩梦”--定域实在论与EPR佯谬", "goals": "理解20世纪物理学最核心的一场思想论战。掌握“定域性”和“实在性”这两个基本概念，并能清晰地阐述爱因斯坦等人提出的EPR佯谬为何对当时的量子力学构成了巨大的挑战。", "activities": [{"day": "1-3", "title": "物理学的基石：什么是“定域实在论”？ (The Bedrock of Physics: What is ''Local Realism''?)", "duration": "约90分钟，可在3天内完成", "description": "研究员，欢迎你进入“伊卡洛斯计划”中最具挑战性的项目之一。在这里，我们将不再仅仅是观察现象，而是要探究现象背后最底层的实在（Reality）结构。\n在我们尝试将物理学工具用于生命科学之前，我们必须首先理解这件工具本身。我们的旅程，始于阿尔伯特·爱因斯坦的一个深刻信念，以及他认为量子力学是一个“不完备”理论的理由。这个信念，被称为**“定域实在论”（Local Realism）**。\n这个词听起来很复杂，但它是由两个我们日常生活中根深蒂固的直觉组成的。\n第一部分：什么是“实在性”（Realism）？\n“实在性”原则，也被称为“客观实在性”，它的意思是：\n一个物体的属性（比如它的位置、颜色、速度），是在我们观察它之前就已经确定存在的客观事实，不依赖于我们的观察行为。\n一个生活中的例子： 你桌上的苹果，在你没有看它的时候，它确实是红色的，并且确实在那里。它的红色和位置不是在你睁开眼睛看它的那一刻才“变”出来的。\n月亮的比喻： 爱因斯坦曾经问他的朋友：“你是否真的相信，月亮只有在我们看它的时候才存在？” 这句话完美地诠释了“实在性”的信念。\n第二部分：什么是“定域性”（Locality）？\n“", "deliverables": ["你的概念辨析：", "在下方的文本框中，用你自己的话，分别对“实在性”和“定域性”做出解释，并各举一个生活中的例子", "格式："]}, {"day": "4-7", "title": "EPR佯谬：爱因斯坦的“幽灵般的超距作用” (The EPR Paradox: Einstein''s ''Spooky Action at a Distance'')", "duration": "约120分钟，可在4天内完成", "description": "1935年，爱因斯坦、波多尔斯基和罗森（Einstein, Podolsky, Rosen）发表了一篇震撼物理学界的论文，提出了一个思想实验，后被称为**“EPR佯谬”**。他们的目的，是想证明量子力学是不完备的。\n这个佯谬的核心，就是我们熟悉的**“量子纠缠”（Quantum Entanglement）**。\n场景设置：\n想象一个黑箱子，里面有一副手套，一只是左手手套，一只是右手手套。我们不知道哪只是哪只。\n现在，我们不看箱子，随机地把两只手套分别装进两个一模一样的小盒子，密封起来。然后，用超光速火箭把一个小盒子送到遥远的织女星（距离地球25光年）。\n实验开始：\n你在地球上，打开你手中的盒子。你发现里面是一只左手手套。\n关键问题： 在你打开盒子的那一瞬间，你是否立刻、马上、毫不迟疑地知道了织女星上那个盒子里装的是什么？\n答案是：当然！你立刻知道了那里面必然是一只右手手套。\n爱因斯坦的论证来了：\n爱因斯坦会说，这很简单，因为“实在性”！那只右手手套的“右”这个属性，是在它被装进盒子的那一刻就已经确定了的客观事实。你打开盒子，只是“发现”了这个事实，你并没有“创造”它。织女星上的那只手套", "deliverables": ["你的角色扮演论述：", "在下方的文本框中，请你扮演爱因斯坦，给量子力学的支持者（比如玻尔）写一封简短的信，来阐述你为什么无法接受“幽灵般的超距作用”，并坚信一定有“隐藏变量”的存在", "要求： 你的信中必须清晰地使用到“定域性”和“实在性”这两个概念来支撑你的论点"]}]}, {"week": 2, "theme": "第二周：贝尔的“审判”--将哲学问题转化为可检验的数学", "goals": "概念性地理解贝尔定理（Bell''s Theorem）的革命性意义。明白贝尔不等式是如何为“定域实在论”设下一个数学“陷阱”的，并理解为什么实验结果违反了这个不等式，就意味着爱因斯坦的世界观可能是错误的。", "activities": [{"day": "8-10", "title": "贝尔定理的核心思想：关联性的“经典上限” (The Core Idea of Bell''s Theorem: The ''Classical Limit'' of Correlation)", "duration": "约90分钟，可在3天内完成", "description": "研究员，上周我们看到，爱因斯坦和玻尔的争论似乎陷入了一个哲学僵局。爱因斯坦说：“一定有隐藏的指令！” 玻尔说：“世界在被观察前就是模糊的！” 谁也说服不了谁。\n直到1964年，物理学家约翰·贝尔（John Bell）提出了一个天才的想法。他想：“好吧，我们先假设爱因斯坦是对的。如果世界真的是由‘定域实在论’所支配的，那么，两个相互分离的、被测量的物体，它们结果之间的‘关联性’，会不会有一个数学上的上限？”\n这个“上限”，就是贝尔不等式（Bell''s Inequality）。它就像是贝尔为“定域实在论”这个“嫌疑人”量身定做的一副手铐。\n为了理解这个“上限”是怎么来的，让我们升级一下上周的《纠缠的手套》实验。\n新的设定：\n想象我们有一台机器，它每次会生产出一对机器人（A和B）。每个机器人在出厂时，内部都被预先编程了三个“隐藏指令”，分别对应回答三个不同的问题。这三个问题都是“是否”题，比如：\n问题1 (颜色): 你喜欢红色吗？ (回答: 是/否)\n问题2 (形状): 你喜欢圆形吗？ (回答: 是/否)\n问题3 (质地): 你喜欢光滑吗？ (回答: 是/否)\n机器的编程规则是：对于同一对机", "deliverables": ["你的逻辑推理：", "在下方的文本框中，尝试用你自己的话，向一个没学过这个课程的朋友解释，为什么在一个“答案预设”的世界里，不同问题之间的关联性会有一个“上限”", "格式： “亲爱的朋友，想象一下我们班同学的特点"]}, {"day": "11-14", "title": "审判日：量子力学的预测与实验验证 (Judgment Day: Quantum Mechanics'' Prediction & The Experimental Verdict)", "duration": "约90分钟，可在4天内完成", "description": "研究员，贝尔的法庭已经建立，手铐（贝尔不等式）也已铸好。现在，是时候传唤“被告”--量子力学了。\n贝尔做的第二件伟大的事，就是计算出：如果量子力学的“叠加态”和“坍缩”理论是正确的，那么在《诚实的机器人》实验中，不同问题之间的关联性会是怎样的？\n量子力学的预测：\n量子力学做出了一个惊人的预测。它说，如果那些机器人是“量子机器人”（即它们的属性在被测量前处于叠加态，并且彼此纠缠），那么在特定的问题角度下，它们回答的关联性将会超出贝尔不等式所设定的“经典上限”。\n换句话说，量子力学预测：\nP(A1=B2) + P(A2=B3) < P(A1=B3) （在某些特定条件下）\n这意味着，量子纠缠所产生的关联性，比任何基于“预设指令”的经典理论所能允许的关联性都要强！\n审判的时刻：\n贝尔的理论发表后，物理学家们终于有了一个清晰的、可以进行实验判决的方案了！\n如果实验结果满足贝尔不等式 -> 爱因斯坦获胜，定域实在论成立，量子力学不完备。\n如果实验结果违反贝尔不等式 -> 量子力学获胜，定域实在论被推翻。这意味着，我们必须放弃“实在性”（物体属性在测量前就已确定）或“定域性”（不存在超距作用）中的至", "deliverables": ["你的“法庭判决书”：", "在下方的文本框中，请你扮演法官，写一份关于“定域实在论 vs 量子力学”一案的判决书", "要求： 你的判决书中需要包含：原告（爱因斯坦等）、被告（量子力学）、关键证据（贝尔不等式及其被实验违反）、以及最终判决和判决理由"]}]}, {"week": 3, "theme": "第三周：思想的迁徙--构建生物版的“贝尔实验”", "goals": "学习如何进行类比推理和模型构建。将物理学中“纠缠光子对”的贝尔实验模型，类比到“主人-宠物”系统上，定义出生物学版本的“测量”、“设置”和“结果”，并进行第一次初步的、概念性的实验设计。", "activities": [{"day": "15-17", "title": "类比的艺术：从光子到生命体 (The Art of Analogy: From Photons to Living Beings)", "duration": "约90分钟，可在3天内完成", "description": "研究员，我们已经站在了现代物理学的巅峰，亲眼见证了“定域实在论”的坍塌。现在，我们要做的，是一件更大胆、也更具原创性的事：我们能否借用贝尔的“审判工具”，来审视我们最初的那个谜题--人与动物之间的无形纽dài？\n这需要一种强大的思维能力，叫做**“类比推理”（Analogical Reasoning）**。我们需要在两个看似完全不同的系统之间，找到其底层的逻辑对应关系。\n让我们来分解阿斯佩（Aspect）等人经典的贝尔实验，看看它的核心组件是什么，然后尝试为它们找到生物学上的“替身”。\n物理贝尔实验组件 (Physics Model)\n生物贝尔实验类比 (Biological Analogy)\n你的思考与定义\n纠缠粒子源 (Source of Entangled Pairs)\n“纠缠”的主人-宠物对 (An ''Entangled'' Human-Pet Pair)\n我们如何定义一对“纠缠”的、有深度情感连接的主人与宠物？\n两个分离的探测器 (Detector A & B)\n两个分离的实验室 (Lab A & B)\n这很简单，就是把主人和宠物分开足够远的距离。\n随机变化的“测量设置” (R", "deliverables": ["你的“生物贝尔实验组件”定义：", "在下方的文本框中，为你自己设想的生物贝尔实验，清晰地定义出以下四个核心组件：", "格式："]}, {"day": "18-21", "title": "绘制蓝图：你的第一个思想实验方案 (Blueprint: Your First Thought Experiment Protocol)", "duration": "约120分钟，可在4天内完成", "description": "研究员，你已经定义好了实验的核心组件。现在，我们要像爱因斯坦构建EPR佯谬一样，构建一个完整的**思想实验（Thought Experiment）**方案。\n思想实验是理论物理学家的强大工具。我们暂时不考虑现实中的技术困难和成本，只在逻辑上构建一个完美的、无懈可击的实验流程。这能帮助我们看清理论的核心，并为未来真正的实验指明方向。\n请你根据上一个任务定义的组件，撰写一份详细的《生物贝尔实验思想实验方案》。这份方案需要回答以下所有问题：\n研究对象 (The Pair):\n如何招募和筛选“主人-宠物对”？需要签署知情同意书吗？（伦理考量）\n实验环境 (The Labs):\n两个实验室A（主人所在地）和B（宠物所在地）需要满足什么条件？（例如：相距至少100公里、电磁屏蔽、隔音、温湿度恒定）。\n同步与随机化 (Synchronization & Randomization):\n如何确保两个实验室的“刺激”和“测量”在时间上是精确同步的？（例如：使用GPS原子钟同步）。\n如何实现“测量设置”的真随机选择？（例如：在每次试验开始前的最后一微秒，由一个量子随机数生成器决定双方的刺激类型）。为什么要", "deliverables": ["你的《生物贝尔实验思想实验方案》：", "在下方的文本框中，打字输入你撰写的、完整的思想实验方案", "请确保你的方案回答了上述所有6个问题"]}]}, {"week": 4, "theme": "第四周：从理想到现实--设计一个“足够好”的实验", "goals": "学习“理想实验”与“现实实验”之间的差异，分析上周设计的思想实验在现实中执行的主要障碍。通过权衡与创新，设计一个“简化但核心思想不变”的、具有初步可操作性的真实生物贝尔实验方案。", "activities": [{"day": "22-24", "title": "现实的挑战：我们的思想实验有哪些障碍？ (The Reality Check: Obstacles for Our Thought Experiment)", "duration": "约90分钟，可在3天内完成", "description": "研究员，上周我们像理论物理学家一样，在思想的白板上构建了一座宏伟的理论大厦。它逻辑自洽、完美无瑕。\n现在，我们要切换身份，成为一名工程师和项目经理。我们的任务是：审视这座“大厦”的设计图，并回答一个残酷的问题：“以我们现有的资源和技术，这东西能造出来吗？如果不能，最大的障碍是什么？”\n让我们逐一审视上周《思想实验方案》中的每一个环节，看看现实的“拦路虎”在哪里。\n“纠缠对”的选择：\n理想： 找到情感连接极强的“纠缠”对。\n现实： “情感连接强度”是一个主观描述，无法量化。我们如何能确定我们找到的这对组合，真的处于某种特殊的“纠缠态”？也许绝大多数宠物和主人之间并没有这种连接。这是一个样本筛选的巨大难题。\n实验环境：\n理想： 两个相距百公里、电磁屏蔽、绝对隔音的专业实验室。\n现实： 成本极高，几乎不可能实现。在家庭环境中，我们无法做到绝对的电磁屏蔽和隔音。\n精确同步与快速随机化：\n理想： GPS原子钟同步，微秒级随机指令下达。\n现实： 虽然技术上可行，但对设备要求很高。更重要的是，生物体的反应速度（神经传导、激素分泌）远比光子的反应慢得多，是毫秒甚至秒级的。微秒级的同步对于生物系统来说可", "deliverables": ["你的“最大障碍分析”：", "在下方的文本框中，从上述5个障碍中，选出你认为最致命的、最难解决的两个，并说明你的理由", "格式："]}, {"day": "25-28", "title": "“足够好”的设计：一个可行的简化方案 (A ''Good Enough'' Design: A Feasible Simplified Protocol)", "duration": "约120分钟，可在4天内完成", "description": "研究员，既然完美的方案无法实现，我们就必须做出选择。现在，我们要做的，就是设计一个**“简化版”的生物贝尔实验。它的目标不再是“一劳永逸地证明非定域性”，而是“在一个可控的、小规模的实验中，初步检验是否存在超越经典预期的关联性”**。\n我们需要在“理想的严谨性”和“现实的可行性”之间找到一个最佳的平衡点。\n让我们针对上一个任务找出的障碍，进行头脑风暴，寻找创新的解决方案。\n障碍： 生理指标测量困难。\n解决方案： 放弃复杂的生理指标，回归到更简单、但同样可量化的“行为指标”！ 我们可以借鉴“杰提计划”的思路，但要升级。\n创新想法： 设计一个二选一的行为任务。例如，在宠物面前放置两个完全相同的食盆（A和B），里面都没有食物。在远方的主人，通过量子随机数，被指令“意念集中在A盆”或“意念集中在B盆”。我们测量的“结果”就是，宠物在接收到信号（比如一声蜂鸣）后的10秒内，首先去闻哪一个食盆。这是一个清晰的、二元的（A/B）行为结果。\n障碍： 实验环境要求高，样本量大。\n解决方案： 放弃多地实验室，采用“时间换空间”的思路，并在个人家庭环境中创造“相对隔离”。\n创新想法： 我们可以不用两个遥远的", "deliverables": ["你的《简化版生物贝尔实验方案》：", "在下方的文本框中，打字输入你根据上述指南和自己的创新想法，撰写的、完整的、可操作的实验方案", "请确保方案的每一步都清晰具体，让你的同学看了之后就知道该怎么做"]}]}]'::jsonb,
    updated_at = NOW()
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 3;

-- Project 4: 第一阶段：植物的悄悄话
UPDATE course_contents
